/* Extreu tots els links rellevants utilitzant lògica nativa JSON/API per a Tauler i Contractació, i Regex massiu per HTML */

const FONTS = [
  {
    nom: 'Acords JGL',
    baseUrl: 'https://ciutada.platjadaro.com',
  },
  {
    nom: 'E-tauler',
    baseUrl: 'https://tauler.seu-e.cat',
  },
  {
    nom: 'Perfil Contractant',
    baseUrl: 'https://contractaciopublica.cat',
  },
];

const resultats = [];
const urlsVistes = new Set();

// 1. Acords JGL (HTML Scrape agressiu per a PDFs de Junta)
const htmlJunta = items[0]?.json?.data || items[0]?.json?.body || '';
if (htmlJunta && typeof htmlJunta === 'string') {
  // Buscar qualsevol href que sigui un PDF a wp-content
  const hrefPattern = /href=["']([^"'\s]+\/wp-content\/uploads\/(2025|2026)\/[^"'\s]+\.pdf)["']/gi;
  let match;
  while ((match = hrefPattern.exec(htmlJunta)) !== null) {
    let url = match[1].trim();
    if (url.startsWith('//')) url = 'https:' + url;
    if (url.startsWith('/')) url = FONTS[0].baseUrl + url;
    if (urlsVistes.has(url)) continue;
    urlsVistes.add(url);
    resultats.push({
      json: {
        url_original: url,
        font: FONTS[0].nom,
        tipus: 'PDF',
        titol_api: url.split('/').pop().replace('.pdf', ''),
        descripcio_api: ''
      }
    });
  }
}

// 2. E-Tauler (API JSON)
const jsonTauler = items[1]?.json?.edictes || [];
if (Array.isArray(jsonTauler)) {
  for (const edicte of jsonTauler) {
    const url = `https://tauler.seu-e.cat/inici?idEns=1704860009&edicte=${edicte.id_edicte}`;
    if (urlsVistes.has(url)) continue;
    urlsVistes.add(url);
    resultats.push({
      json: {
        url_original: url,
        font: FONTS[1].nom,
        tipus: 'edicte',
        titol_api: edicte.titol,
        descripcio_api: edicte.descripcio || ''
      }
    });
  }
}

// 3. Contractació Open Data (API JSON array)
const jsonContractacio = items[2]?.json || [];
if (Array.isArray(jsonContractacio)) {
  for (const contracte of jsonContractacio) {
    const url = contracte.enllac_al_perfil_del_contractant || contracte.link || `https://contractaciopublica.cat/ca/perfils-contractant/detall/3156875?expedient=${contracte.codi_expedient || ''}`;
    if (urlsVistes.has(url) || !url.startsWith('http')) continue;
    urlsVistes.add(url);
    resultats.push({
      json: {
        url_original: url,
        font: FONTS[2].nom,
        tipus: 'licitació',
        titol_api: contracte.denominacio_de_l_acord || contracte.objecte_del_contracte || contracte.titol || 'Contracte de Platja d\'Aro',
        descripcio_api: `Expedient: ${contracte.codi_expedient || '-'}. Import: ${contracte.pressupost_de_licitacio || '-'} €. Adjudicatari: ${contracte.adjudicatari || 'Pendent'}.`
      }
    });
  }
}

console.log(`[INFO] Total URLs candidates trobades: ${resultats.length}`);
return resultats.length > 0 ? resultats : [{ json: { _cap_url: true } }];

/* NOTA: Aquest node rep la resposta de Supabase com a $input.
   Accedeix als URLs extrets del node anterior via $('Code - Extreu tots els links').all()
   Filtra i retorna NOMÉS les URLs que no s'han processat mai. */

// 1. Obtenir URLs ja registrades a Supabase
const supabaseResponse = $input.all();
const urlsJaProcessades = new Set();

for (const item of supabaseResponse) {
  const data = item.json;
  // La resposta de Supabase pot ser un array directe o via { data: [] }
  const registres = Array.isArray(data) ? data : (data?.data || []);
  for (const r of registres) {
    if (r?.url_original) urlsJaProcessades.add(r.url_original);
  }
}

console.log(`[INFO] URLs ja processades a Supabase: ${urlsJaProcessades.size}`);

// 2. Obtenir URLs candidates del node d'extracció
let urlsCandidates;
try {
  urlsCandidates = $('Code - Extreu tots els links').all();
} catch (e) {
  console.error('[ERROR] No es pot accedir als resultats del node extracció:', e.message);
  return [];
}

// 3. Filtrar les noves
const noves = urlsCandidates.filter(item => {
  const url = item.json?.url_original;
  if (!url || item.json?._cap_url) return false;
  return !urlsJaProcessades.has(url);
});

console.log(`[INFO] URLs candidates: ${urlsCandidates.length} | Noves a processar: ${noves.length}`);

if (noves.length === 0) {
  console.log('[INFO] Cap novetat detectada en aquesta execució.');
  return [{ json: { _cap_novetat: true, total: 0 } }];
}

// Retornar màxim 20 per execució per evitar timeout
const limit = 20;
const novasFiltrades = noves.slice(0, limit);
if (noves.length > limit) {
  console.log(`[WARN] ${noves.length} URLs noves. Processant les primeres ${limit}.`);
}

return novasFiltrades;

/* Extreu el text llegible del HTML/PDF i prepara les metadades per OpenAI */

const httpResponse  = $input.item.json;
const loopItem      = $('Loop - Processa cada URL').item.json;

const statusCode    = httpResponse?.statusCode || 200;
const rawBody       = httpResponse?.data || httpResponse?.body || '';
const urlOriginal   = loopItem.url_original;
const font          = loopItem.font;
const tipus         = loopItem.tipus;

let textExtret         = '';
let confiancaBase      = 'ALTA';
let requereixRevisio   = false;

if (statusCode >= 400 || !rawBody) {
  textExtret       = `Error HTTP ${statusCode}. No s'ha pogut obtenir el contingut de la URL.`;
  confiancaBase    = 'BAIXA';
  requereixRevisio = true;

} else if (tipus === 'PDF' || urlOriginal.toLowerCase().includes('.pdf')) {
  // PDF textual: extreure text pla
  const textRaw = typeof rawBody === 'string' ? rawBody.replace(/\s+/g, ' ').trim() : '';
  if (textRaw.length < 80) {
    textExtret       = `PDF escanejat o protegit. Nom del fitxer: ${urlOriginal.split('/').pop()}`;
    confiancaBase    = 'BAIXA';
    requereixRevisio = true;
  } else {
    textExtret = textRaw.slice(0, 10000);
  }

} else {
  // HTML: netejar i extreure text principal
  let textNet = rawBody
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
    .replace(/<footer[\s\S]*?<\/footer>/gi, ' ')
    .replace(/<header[\s\S]*?<\/header>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"')
    .replace(/&#[0-9]+;/g, ' ').replace(/\s{2,}/g, ' ').trim();

  if (textNet.length < 80) {
    confiancaBase = 'MITJA';
    textExtret    = `Contingut HTML insuficient (possible pàgina renderitzada per JS). URL: ${urlOriginal}`;
  } else {
    textExtret = textNet.slice(0, 8000);
  }
}

// Injectar dades de les APIs rescatades
if (loopItem.descripcio_api) {
  textExtret = `\n[INFORMACIÓ API DE LA FONT]:\n${loopItem.descripcio_api}\n\n[TEXT RASPATEJAT]:\n${textExtret}`;
  if (confiancaBase === 'BAIXA') confiancaBase = 'MITJA';
}

const titolFinal = loopItem.titol_api || decodeURIComponent(urlOriginal.split('/').pop().replace(/[?#].*$/, '').replace(/[-_]/g, ' ').replace(/\.pdf$/i, '').trim()) || urlOriginal;

return {
  json: {
    url_original:          urlOriginal,
    font:                  font,
    tipus:                 tipus,
    titol_provisional:     titolFinal.slice(0, 300),
    contingut_complet:     textExtret,
    confianca_base:        confiancaBase,
    requereix_revisio:     requereixRevisio,
  }
};

/* Parseja la resposta de la IA i aplica les REGLES FIXES d'urgència (DER §5.2).
   Les regles fixes tenen PRIORITAT MÀXIMA sobre la classificació de la IA. */

// Obtenir la resposta de la IA
const iaText = $input.item.json?.message?.content
  || $input.item.json?.choices?.[0]?.message?.content
  || '';

// Dades originals del node de preparació
const original = $('Code - Prepara contingut per a IA').item.json;

// ─── Parser del format de resposta ───────────────────────────────────────
function camp(text, clau) {
  const regex = new RegExp(`^${clau}:\\s*(.+)$`, 'mi');
  const m = text.match(regex);
  return m ? m[1].trim() : null;
}

function parseImport(str) {
  if (!str || /no detectat/i.test(str) || /no aplicable/i.test(str)) return null;
  // Eliminar símbols i convertir coma decimal
  const net = str.replace(/[€$£\s.]/g, '').replace(',', '.');
  const val = parseFloat(net);
  return isNaN(val) || val <= 0 ? null : val;
}

function parseData(str) {
  if (!str || /no detectat/i.test(str)) return null;
  // Format DD/MM/YYYY → YYYY-MM-DD
  const m = str.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if (!m) return null;
  const [, d, mo, y] = m;
  // Validar data
  const dt = new Date(`${y}-${mo.padStart(2,'0')}-${d.padStart(2,'0')}`);
  if (isNaN(dt.getTime())) return null;
  return `${y}-${mo.padStart(2,'0')}-${d.padStart(2,'0')}`;
}

function parseBoolean(str) {
  if (!str) return false;
  return /^sí/i.test(str.trim());
}

// ─── Extreure camps ───────────────────────────────────────────────────────
const titolIA        = camp(iaText, 'TÍTOL') || camp(iaText, 'TITOL') || original.titol_provisional;
const urgenciaIA     = camp(iaText, 'URGÈNCIA') || camp(iaText, 'URGENCIA') || 'INFORMATIU';
const resumIA        = camp(iaText, 'RESUM') || camp(iaText, 'RESUm') || 'Resum no disponible.';
const vencimentStr   = camp(iaText, 'VENCIMENT');
const importStr      = camp(iaText, 'IMPORT');
const temaIA         = camp(iaText, 'TEMA') || 'altres';
const confiancaIA    = camp(iaText, 'CONFIANÇA') || camp(iaText, 'CONFIANCA') || 'MITJA';
const propostaIA     = camp(iaText, 'PROPOSTA');
const preguntaIA     = camp(iaText, 'PREGUNTA_PLE') || camp(iaText, 'PREGUNTA PLE');
const expedientStr   = camp(iaText, 'EXPEDIENT');

const venciment      = parseData(vencimentStr);
const importDetectat = parseImport(importStr);
const calExpedient   = parseBoolean(expedientStr);

// Neteja de valors "No aplicable"
const proposta = (propostaIA && !/no aplicable/i.test(propostaIA)) ? propostaIA : null;
const pregunta = (preguntaIA && !/no aplicable/i.test(preguntaIA)) ? preguntaIA : null;

// ─── REGLES FIXES D'URGÈNCIA (DER §5.2) — Prioritat sobre IA ─────────────
let classificacio    = urgenciaIA.toUpperCase();
if (!['URGENT','IMPORTANT','INFORMATIU'].includes(classificacio)) classificacio = 'INFORMATIU';

let reglaActivada    = null;
const avui           = new Date();
avui.setHours(0, 0, 0, 0);

// Regla 1: Venciment legal pròxim (<15 dies) → URGENT obligatori
if (venciment) {
  const diesRestants = Math.ceil((new Date(venciment) - avui) / 86_400_000);
  if (diesRestants > 0 && diesRestants < 15) {
    classificacio = 'URGENT';
    reglaActivada = `Venciment en ${diesRestants} dies`;
  }
}

// Regla 2: Import > 50.000€ → mínim IMPORTANT
if (importDetectat && importDetectat > 50_000 && classificacio === 'INFORMATIU') {
  classificacio = 'IMPORTANT';
  reglaActivada = `Import ${importDetectat.toLocaleString('ca-ES')} € > 50.000€`;
}

// Regla 3: Tema contractació → mínim IMPORTANT
const esContractacio = ['contractació','licitació','adjudicació'].includes(temaIA.toLowerCase());
if (esContractacio && classificacio === 'INFORMATIU') {
  classificacio = 'IMPORTANT';
  reglaActivada = 'Tema contractació pública';
}

// Regla 4: PDF de Junta de Govern → mínim IMPORTANT
if (original.font === 'Acords JGL' && original.tipus === 'PDF' && classificacio === 'INFORMATIU') {
  classificacio = 'IMPORTANT';
  reglaActivada = 'PDF Junta de Govern Local';
}

if (reglaActivada) {
  console.log(`[REGLA FIXA] ${urgenciaIA} → ${classificacio} (${reglaActivada}): ${titolIA?.slice(0,60)}`);
}

// ─── Confiança final (la més baixa entre IA i base) ──────────────────────
const NIVELLS       = { 'ALTA': 3, 'MITJA': 2, 'BAIXA': 1 };
const nivellFinal   = Math.min(NIVELLS[confiancaIA] || 2, NIVELLS[original.confianca_base] || 2);
const confianca     = Object.keys(NIVELLS).find(k => NIVELLS[k] === nivellFinal) || 'MITJA';

// ─── Inferir tipus_document ───────────────────────────────────────────────
const TIPOS_MAP = {
  'contractació': 'contracte', 'licitació': 'licitació',
  'adjudicació': 'adjudicació', 'urbanisme': 'edicte',
  'pressupost': 'acord', 'personal': 'acord',
};
const tipusDocument = TIPOS_MAP[temaIA.toLowerCase()] || (original.tipus === 'PDF' ? 'acord' : 'edicte');

// ─── Alerta individual (per a Telegram urgent) ────────────────────────────
const esAlertaIndividual = classificacio === 'URGENT'
  || (importDetectat !== null && importDetectat > 100_000)
  || calExpedient;

console.log(`[PROCESSAT] ${classificacio} | ${confianca} | ${titolIA?.slice(0,50)}`);

return {
  json: {
    // Camps BD Supabase
    url_original:            original.url_original,
    font:                    original.font,
    tipus:                   original.tipus,
    tipus_document:          tipusDocument,
    titol:                   (titolIA || original.titol_provisional).slice(0, 500),
    contingut_complet:       original.contingut_complet,
    resum:                   resumIA.slice(0, 2000),
    classificacio:           classificacio,
    nivell_confianca:        confianca,
    data_deteccio:           new Date().toISOString(),
    venciment:               venciment,
    import_detectat:         importDetectat,
    tema_principal:          temaIA.toLowerCase().slice(0, 50),
    proposta_accio:          proposta ? proposta.slice(0, 1000) : null,
    pregunta_ple_suggerida:  pregunta ? pregunta.slice(0, 1000) : null,
    requereix_revisio_manual: original.requereix_revisio || confianca === 'BAIXA',
    estat_seguiment:         'pendent',
    observacions:            null,
    estat:                   'nou',
    // Metadades per a missatgeria (no van a BD)
    _alerta_individual:      esAlertaIndividual,
    _regla_activada:         reglaActivada,
    _cal_expedient:          calExpedient,
  }
};

/* Agrega tots els resultats del loop i construeix:
   - Missatge Telegram (MarkdownV2, agrupat per urgència)
   - Correu HTML (formatat, tots els detalls) */

// Recopila tots els items processats durant el loop
let totsElsItems;
try {
  totsElsItems = $('Code - Parseja IA i aplica regles').all();
} catch {
  totsElsItems = items; // Fallback
}

const novetats = totsElsItems
  .map(i => i.json)
  .filter(r => r?.titol && r?.url_original && !r?._cap_novetat)
  .sort((a, b) => {
    const ordre = { URGENT: 0, IMPORTANT: 1, INFORMATIU: 2 };
    return (ordre[a.classificacio] ?? 3) - (ordre[b.classificacio] ?? 3);
  });

if (novetats.length === 0) {
  return [{ json: { total: 0, missatgeTelegram: '', missatgeEmail: '', novetats: [], alertesIndividuals: [] } }];
}

const ara     = new Date();
const torn    = ara.getHours() < 14 ? 'matí' : 'tarda';

const DIES    = ['Diumenge','Dilluns','Dimarts','Dimecres','Dijous','Divendres','Dissabte'];
const MESOS   = ['gener','febrer','març','abril','maig','juny','juliol','agost','setembre','octubre','novembre','desembre'];
const dataStr = `${DIES[ara.getDay()]}, ${ara.getDate()} de ${MESOS[ara.getMonth()]} del ${ara.getFullYear()}`;

const EMOJI   = { URGENT: '🔴', IMPORTANT: '🟡', INFORMATIU: '🟢' };
const CONF    = { ALTA: '✅', MITJA: '⚠️', BAIXA: '❌' };
const COLORS  = { URGENT: '#f87171', IMPORTANT: '#fbbf24', INFORMATIU: '#4ade80' };

// ─── TELEGRAM MarkdownV2 ─────────────────────────────────────────────────
function esc(t) {
  return String(t || '').replace(/([_*\[\]()~`>#+\-=|{}.!])/g, '\\$1');
}

let tg = `*🏛 Monitor Polític — ${esc(dataStr)} \\(${torn}\\)*\n`;
tg    += `*${esc(novetats.length.toString())} novetats detectades*\n`;
tg    += `${esc('─'.repeat(28))}\n\n`;

for (const n of novetats.slice(0, 10)) {
  const venc = n.venciment ? `\n⏰ *Venciment: ${esc(n.venciment)}*` : '';
  const imp  = n.import_detectat ? `\n💶 Import: *${esc(n.import_detectat.toLocaleString('ca-ES'))} €*` : '';
  tg += `${EMOJI[n.classificacio] || '⚪'} *${esc(n.titol.slice(0,80))}*\n`;
  tg += `📂 ${esc(n.font)} · ${esc(n.tema_principal || '')}${venc}${imp}\n`;
  tg += `${CONF[n.nivell_confianca] || ''} _${esc(n.resum.slice(0,200))}_\n`;
  if (n.proposta_accio) tg += `💡 _${esc(n.proposta_accio.slice(0,120))}_\n`;
  tg += `🔗 [Veure el document](${n.url_original})\n\n`;
}

if (novetats.length > 10) {
  tg += `\n_\\+${novetats.length - 10} novetats addicionals al dashboard_\n`;
}

// ─── EMAIL HTML ──────────────────────────────────────────────────────────
const GREEN = '#4ade80';

let email = `<!DOCTYPE html><html lang="ca"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Inter,sans-serif;background:#0c0e14;color:#f0f2f8;padding:24px;margin:0;">
<div style="max-width:680px;margin:0 auto;">
  <div style="border-bottom:2px solid #4ade80;padding-bottom:16px;margin-bottom:24px;">
    <h1 style="font-size:1.375rem;font-weight:700;margin:0 0 4px;">🏛 Monitor Polític Municipal</h1>
    <p style="color:#8891a8;margin:0;font-size:0.875rem;">${dataStr} · ${torn} · ${novetats.length} novetats</p>
  </div>`;

for (const n of novetats) {
  const col  = COLORS[n.classificacio] || '#8891a8';
  email += `<div style="border:1px solid ${col}33;border-left:4px solid ${col};border-radius:10px;padding:18px;margin-bottom:16px;background:#161924;">`;
  email += `  <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;flex-wrap:wrap;">`;
  email += `    <span style="background:${col}22;color:${col};padding:3px 10px;border-radius:4px;font-size:0.75rem;font-weight:700;letter-spacing:0.04em;">${n.classificacio}</span>`;
  email += `    <span style="color:#525c72;font-size:0.75rem;">${n.font} · ${n.tema_principal || ''}</span>`;
  if (n.nivell_confianca === 'BAIXA') email += `    <span style="color:#f87171;font-size:0.7rem;">⚠️ Confiança ${n.nivell_confianca}</span>`;
  email += `  </div>`;
  email += `  <h2 style="font-size:0.9375rem;font-weight:700;margin:0 0 8px;line-height:1.4;">${n.titol}</h2>`;
  email += `  <p style="font-size:0.875rem;color:#b0b8cc;margin:0 0 10px;line-height:1.6;">${n.resum}</p>`;
  if (n.import_detectat) email += `  <p style="color:${GREEN};font-size:0.8125rem;margin:0 0 6px;">💶 <strong>${n.import_detectat.toLocaleString('ca-ES')} €</strong></p>`;
  if (n.venciment) email += `  <p style="color:#f87171;font-size:0.8125rem;margin:0 0 6px;">⏰ Venciment: <strong>${n.venciment}</strong></p>`;
  if (n.proposta_accio) email += `  <div style="border-top:1px solid #2a2f3d;margin-top:10px;padding-top:10px;"><p style="color:#8891a8;font-size:0.8125rem;margin:0;">💡 ${n.proposta_accio}</p></div>`;
  if (n.pregunta_ple_suggerida) email += `  <p style="color:#60a5fa;font-size:0.8125rem;margin:6px 0 0;">❓ <em>${n.pregunta_ple_suggerida}</em></p>`;
  email += `  <a href="${n.url_original}" style="display:inline-block;margin-top:12px;color:${GREEN};font-size:0.8125rem;text-decoration:none;">Veure document original →</a>`;
  email += `</div>`;
}

email += `<p style="color:#525c72;font-size:0.7rem;margin-top:24px;padding-top:12px;border-top:1px solid #2a2f3d;">
  Monitor Polític Municipal · Castell-Platja d'Aro · v2.1 · Generat automàticament el ${ara.toLocaleString('ca-ES')}<br/>
  Per a ús intern del regidor de l'oposició. No distribuir.
</p></div></body></html>`;

// ─── Alertes individuals Telegram ─────────────────────────────────────────
const alertesIndividuals = novetats.filter(n => n._alerta_individual);

return [{
  json: {
    total:              novetats.length,
    urgents:            novetats.filter(n => n.classificacio === 'URGENT').length,
    missatgeTelegram:   tg,
    missatgeEmail:      email,
    asumpteEmail:       `🏛 Monitor Polític [${ara.toLocaleDateString('ca-ES')}] — ${novetats.length} novetats (${torn})`,
    alertesIndividuals: alertesIndividuals.map(n => ({
      titol:    n.titol.slice(0, 100),
      resum:    n.resum.slice(0, 200),
      url:      n.url_original,
      venciment: n.venciment,
      import:   n.import_detectat,
      classificacio: n.classificacio,
    })),
    novetats,
  }
}];

