{{ $json.alertesIndividuals.map(a => {
  const esc = t => String(t||'').replace(/([_*\[\]()~`>#+\-=|{}.!])/g, '\\\\$1');
  const venc = a.venciment ? `⏰ Venciment: *${esc(a.venciment)}*\n` : '';
